-- ============================================================
-- AppDiversa - Inserción/actualización de la Encuesta de Discriminación
-- Base objetivo: MySQL 8 / dump appdiversa-data.sql
-- Generado para crear la versión 2 de DISC-001 y dejarla como versión actual
-- Fuente funcional: Cuestionario de Discriminación - Aplicación web multimodular para datos ciudadanos
-- ============================================================
SET NAMES utf8mb4;
SET @now = NOW(6);
START TRANSACTION;

-- 1) Formulario principal
INSERT INTO `formularios_formulario` (
  `uuid`, `codigo`, `nombre`, `descripcion`, `introduccion`, `objetivo`, `tipo_formulario`, `tiempo_estimado_minutos`, `estado`, `version_actual`, `permite_anonimo`, `permite_registro_final`, `permite_multiples_respuestas`, `permite_offline`, `fecha_inicio`, `fecha_fin`, `fecha_creacion`, `fecha_modificacion`, `creado_por_id`, `fecha_eliminacion`, `modificado_por_id`, `eliminado_por_id`, `esta_eliminado`, `imagen_portada`, `imagen_portada_repositorio_id`, `orden`
) VALUES (
  '1b5f64f9cd6648f6b210ce6b371bb8fb', 'DISC-001', 'Encuesta de Discriminación', 'Encuesta ciudadana para recolectar experiencias, percepciones y entornos asociados a discriminación en Colombia.', 'Comparte tus experiencias de discriminación en Colombia para impulsar la igualdad y la inclusión. La encuesta puede ser diligenciada de forma anónima.', 'Recolectar información ciudadana sobre experiencias de discriminación, motivos, espacios y prácticas observadas en el entorno habitual.', 'encuesta', 10, 'publicado', 2, 1, 1, 0, 1, NULL, NULL, @now, @now, NULL, NULL, NULL, NULL, 0, 'formularios/portadas/image_ecu_disponible.png', NULL, 1
)
ON DUPLICATE KEY UPDATE
  `nombre` = VALUES(`nombre`),
  `descripcion` = VALUES(`descripcion`),
  `introduccion` = VALUES(`introduccion`),
  `objetivo` = VALUES(`objetivo`),
  `tipo_formulario` = VALUES(`tipo_formulario`),
  `tiempo_estimado_minutos` = VALUES(`tiempo_estimado_minutos`),
  `estado` = VALUES(`estado`),
  `version_actual` = VALUES(`version_actual`),
  `permite_anonimo` = VALUES(`permite_anonimo`),
  `permite_registro_final` = VALUES(`permite_registro_final`),
  `permite_multiples_respuestas` = VALUES(`permite_multiples_respuestas`),
  `permite_offline` = VALUES(`permite_offline`),
  `fecha_inicio` = VALUES(`fecha_inicio`),
  `fecha_fin` = VALUES(`fecha_fin`),
  `fecha_modificacion` = VALUES(`fecha_modificacion`),
  `creado_por_id` = VALUES(`creado_por_id`),
  `fecha_eliminacion` = VALUES(`fecha_eliminacion`),
  `modificado_por_id` = VALUES(`modificado_por_id`),
  `eliminado_por_id` = VALUES(`eliminado_por_id`),
  `esta_eliminado` = VALUES(`esta_eliminado`),
  `imagen_portada` = VALUES(`imagen_portada`),
  `imagen_portada_repositorio_id` = VALUES(`imagen_portada_repositorio_id`),
  `orden` = VALUES(`orden`);
SET @formulario_id = (SELECT id FROM `formularios_formulario` WHERE codigo = 'DISC-001' LIMIT 1);

-- 2) Versión 2: se conserva la versión anterior y se publica esta como actual
INSERT INTO `formularios_formularioversion` (
  `numero_version`, `estado`, `descripcion_cambio`, `es_publicada`, `fecha_publicacion`, `fecha_creacion`, `formulario_id`, `fecha_modificacion`, `fecha_eliminacion`, `creado_por_id`, `modificado_por_id`, `eliminado_por_id`, `esta_eliminado`
) VALUES (
  2, 'publicado', 'Carga completa del cuestionario de discriminación: capítulos I a IV, preguntas, opciones y matrices.', 1, @now, @now, @formulario_id, @now, NULL, NULL, NULL, NULL, 0
)
ON DUPLICATE KEY UPDATE
  `estado` = VALUES(`estado`),
  `descripcion_cambio` = VALUES(`descripcion_cambio`),
  `es_publicada` = VALUES(`es_publicada`),
  `fecha_publicacion` = VALUES(`fecha_publicacion`),
  `fecha_modificacion` = @now,
  `fecha_eliminacion` = NULL,
  `esta_eliminado` = 0;
SET @cat_departamentos = (SELECT id FROM `catalogos_catalogo` WHERE codigo = 'departamentos' AND esta_eliminado = 0 LIMIT 1);
SET @cat_municipios = (SELECT id FROM `catalogos_catalogo` WHERE codigo = 'municipios' AND esta_eliminado = 0 LIMIT 1);
SET @version_id = (SELECT id FROM `formularios_formularioversion` WHERE formulario_id = @formulario_id AND numero_version = 2 LIMIT 1);
UPDATE `formularios_formularioversion`
SET `es_publicada` = 0, `fecha_modificacion` = @now
WHERE `formulario_id` = @formulario_id AND `numero_version` <> 2;
UPDATE `formularios_formulario` SET `version_actual` = 2, `estado` = 'publicado', `fecha_modificacion` = @now WHERE id = @formulario_id;

-- 2b) Limpieza de preguntas obsoletas de la versión 1 (filtro inicial incorrecto)
SET @version_v1_id = (SELECT id FROM `formularios_formularioversion` WHERE formulario_id = @formulario_id AND numero_version = 1 LIMIT 1);
SET @sec_v1_cap_i = (SELECT id FROM `formularios_seccionformulario` WHERE formulario_version_id = @version_v1_id AND codigo = 'CAP-I' LIMIT 1);
UPDATE `formularios_opcionrespuesta` op
JOIN `formularios_pregunta` p ON p.id = op.pregunta_id
SET op.esta_activa = 0, op.esta_eliminado = 1, op.fecha_eliminacion = @now, op.fecha_modificacion = @now
WHERE p.seccion_id = @sec_v1_cap_i AND op.esta_eliminado = 0;
UPDATE `formularios_pregunta`
SET `esta_activa` = 0, `esta_eliminado` = 1, `fecha_eliminacion` = @now, `fecha_modificacion` = @now
WHERE `seccion_id` = @sec_v1_cap_i AND `esta_eliminado` = 0;

-- 3) Limpieza lógica del contenido previo de la versión 2 para evitar opciones sobrantes
UPDATE `formularios_opcionrespuesta` op
JOIN `formularios_pregunta` p ON p.id = op.pregunta_id
JOIN `formularios_seccionformulario` s ON s.id = p.seccion_id
SET op.esta_activa = 0, op.esta_eliminado = 1, op.fecha_eliminacion = @now, op.fecha_modificacion = @now
WHERE s.formulario_version_id = @version_id;
UPDATE `formularios_preguntamatrizfila` mf
JOIN `formularios_pregunta` p ON p.id = mf.pregunta_id
JOIN `formularios_seccionformulario` s ON s.id = p.seccion_id
SET mf.esta_activa = 0, mf.esta_eliminado = 1, mf.fecha_eliminacion = @now, mf.fecha_modificacion = @now
WHERE s.formulario_version_id = @version_id;
UPDATE `formularios_preguntamatrizcolumna` mc
JOIN `formularios_pregunta` p ON p.id = mc.pregunta_id
JOIN `formularios_seccionformulario` s ON s.id = p.seccion_id
SET mc.esta_activa = 0, mc.esta_eliminado = 1, mc.fecha_eliminacion = @now, mc.fecha_modificacion = @now
WHERE s.formulario_version_id = @version_id;
UPDATE `formularios_pregunta` p
JOIN `formularios_seccionformulario` s ON s.id = p.seccion_id
SET p.esta_activa = 0, p.esta_eliminado = 1, p.fecha_eliminacion = @now, p.fecha_modificacion = @now
WHERE s.formulario_version_id = @version_id;
UPDATE `formularios_seccionformulario`
SET esta_activo = 0, esta_eliminado = 1, fecha_eliminacion = @now, fecha_modificacion = @now
WHERE formulario_version_id = @version_id;

