-- 8) Reglas condicionales parametrizadas
INSERT INTO `formularios_reglapregunta` (`operador`, `valor_esperado`, `accion`, `mensaje`, `esta_activa`, `pregunta_destino_id`, `pregunta_origen_id`, `seccion_destino_id`, `fecha_creacion`, `fecha_modificacion`, `fecha_eliminacion`, `creado_por_id`, `modificado_por_id`, `eliminado_por_id`, `esta_eliminado`)
SELECT 'equals', JSON_OBJECT('valor', 'si'), 'mostrar', '', 1, @preg_p7_ant, @preg_p7, NULL, @now, @now, NULL, NULL, NULL, NULL, 0
WHERE @preg_p7 IS NOT NULL AND @preg_p7_ant IS NOT NULL
  AND NOT EXISTS (
    SELECT 1 FROM `formularios_reglapregunta`
    WHERE pregunta_origen_id = @preg_p7
      AND pregunta_destino_id = @preg_p7_ant
      AND accion = 'mostrar'
      AND esta_eliminado = 0
  );
INSERT INTO `formularios_reglapregunta` (`operador`, `valor_esperado`, `accion`, `mensaje`, `esta_activa`, `pregunta_destino_id`, `pregunta_origen_id`, `seccion_destino_id`, `fecha_creacion`, `fecha_modificacion`, `fecha_eliminacion`, `creado_por_id`, `modificado_por_id`, `eliminado_por_id`, `esta_eliminado`)
SELECT 'equals', JSON_OBJECT('valor', 'si'), 'hacer_obligatoria', '', 1, @preg_p7_ant, @preg_p7, NULL, @now, @now, NULL, NULL, NULL, NULL, 0
WHERE @preg_p7 IS NOT NULL AND @preg_p7_ant IS NOT NULL
  AND NOT EXISTS (
    SELECT 1 FROM `formularios_reglapregunta`
    WHERE pregunta_origen_id = @preg_p7
      AND pregunta_destino_id = @preg_p7_ant
      AND accion = 'hacer_obligatoria'
      AND esta_eliminado = 0
  );
-- Oculta el periodo de discriminacion (P13) cuando P12 marca la opcion excluyente 'No he sentido discriminación'.
INSERT INTO `formularios_reglapregunta` (`operador`, `valor_esperado`, `accion`, `mensaje`, `esta_activa`, `pregunta_destino_id`, `pregunta_origen_id`, `seccion_destino_id`, `fecha_creacion`, `fecha_modificacion`, `fecha_eliminacion`, `creado_por_id`, `modificado_por_id`, `eliminado_por_id`, `esta_eliminado`)
SELECT 'contains', JSON_OBJECT('valores', JSON_ARRAY('OP26-P12', 'no_he_sentido')), 'ocultar', '', 1, @preg_p13, @preg_p12, NULL, @now, @now, NULL, NULL, NULL, NULL, 0
WHERE @preg_p12 IS NOT NULL AND @preg_p13 IS NOT NULL
  AND NOT EXISTS (
    SELECT 1 FROM `formularios_reglapregunta`
    WHERE pregunta_origen_id = @preg_p12
      AND pregunta_destino_id = @preg_p13
      AND accion = 'ocultar'
      AND esta_eliminado = 0
  );

-- Reglas funcionales adicionales sugeridas
-- - Si P12 incluye 'No he sentido discriminación', debe tratarse como opción excluyente.
-- - Si una opción activa_otro = 1, el frontend debe mostrar el campo complementario ¿cuál? / especifique.
-- - P3 y P3-MUN siguen el patron geografico reutilizable: catalogos `geografico`/`jerarquico`,
--   `pregunta_padre_catalogo` para dependencias y agrupacion automatica en una sola pantalla.

-- 9) Verificación rápida
SELECT 'formularios_formulario' AS tabla, COUNT(*) AS total FROM `formularios_formulario` WHERE codigo = 'DISC-001';
SELECT 'version_actual' AS dato, version_actual FROM `formularios_formulario` WHERE codigo = 'DISC-001';
SELECT 'secciones_v2' AS tabla, COUNT(*) AS total FROM `formularios_seccionformulario` WHERE formulario_version_id = @version_id AND esta_activo = 1 AND esta_eliminado = 0;
SELECT 'preguntas_v2' AS tabla, COUNT(*) AS total FROM `formularios_pregunta` p JOIN `formularios_seccionformulario` s ON s.id = p.seccion_id WHERE s.formulario_version_id = @version_id AND p.esta_activa = 1 AND p.esta_eliminado = 0;
SELECT 'opciones_v2' AS tabla, COUNT(*) AS total FROM `formularios_opcionrespuesta` op JOIN `formularios_pregunta` p ON p.id = op.pregunta_id JOIN `formularios_seccionformulario` s ON s.id = p.seccion_id WHERE s.formulario_version_id = @version_id AND op.esta_activa = 1 AND op.esta_eliminado = 0;
SELECT 'filas_matriz_v2' AS tabla, COUNT(*) AS total FROM `formularios_preguntamatrizfila` mf JOIN `formularios_pregunta` p ON p.id = mf.pregunta_id JOIN `formularios_seccionformulario` s ON s.id = p.seccion_id WHERE s.formulario_version_id = @version_id AND mf.esta_activa = 1 AND mf.esta_eliminado = 0;
SELECT 'columnas_matriz_v2' AS tabla, COUNT(*) AS total FROM `formularios_preguntamatrizcolumna` mc JOIN `formularios_pregunta` p ON p.id = mc.pregunta_id JOIN `formularios_seccionformulario` s ON s.id = p.seccion_id WHERE s.formulario_version_id = @version_id AND mc.esta_activa = 1 AND mc.esta_eliminado = 0;

COMMIT;
-- Resultado esperado: 4 secciones, 17 preguntas (P3 desglosada en departamento + municipio), 72 opciones, 15 filas de matriz y 8 columnas de matriz.
-- Requisito previo: ejecutar `python manage.py importar_divipola` para poblar los catálogos departamentos y municipios.
